817→export const getFollowingFeedService = async(limit, userId, before) => {
818→    if (!userId) {
819→        throw { status: 401, error: 'authentication required' };
820→    }
821→    if (isNaN(limit) || limit > 20 || limit < 1) {
822→        throw { status: 400, error: 'limit should be integer, not below 1 and higher than 20' };
823→    }
824→
825→    const parsedLimit = parseInt(limit);
826→
827→    // Step 1: Fetch journals via RPC (subquery stays inside Postgres — scales to 100k+ followings)
828→    const { data: rpcData, error } = await supabase.rpc('get_following_feed', {
829→        p_user_id: userId,
830→        p_limit: parsedLimit + 1,
831→        p_before: before || null
832→    });
833→
834→    if (error) {
835→        console.error('supabase error fetching following feed:', error.message);
836→        throw { status: 500, error: 'supabase error fetching following feed' };
837→    }
838→
839→    if (!rpcData || rpcData.length === 0) {
840→        return { data: [], hasMore: false };
841→    }
842→
843→    // Reshape RPC rows to match PostgREST format the client expects
844→    const data = rpcData.map(row => ({
845→        id: row.id,
846→        user_id: row.user_id,
847→        title: row.title,
848→        content: row.content,
849→        post_type: row.post_type,
850→        canvas_doc: row.canvas_doc,
851→        created_at: row.created_at,
852→        privacy: row.privacy,
853→        views: row.views,
854→        is_repost: row.is_repost,
855→        repost_source_journal_id: row.repost_source_journal_id,
856→        repost_caption: row.repost_caption,
857→        prompt_id: row.prompt_id,
858→        users: { id: row.user_obj_id, name: row.user_name, image_url: row.user_image_url, badge: row.user_badge },
859→        like_count: [{ count: Number(row.like_count) }],
860→        reaction_count: [{ count: Number(row.reaction_count) }],
861→        comment_count: [{ count: Number(row.comment_count) }],
862→        bookmark_count: [{ count: Number(row.bookmark_count) }]
863→    }));
864→
865→    // Step 2: Personalization (same pattern as getJournalsService — operates on small result set)
866→    const journalIds = data.map(j => j.id);
867→    const [userLikes, userBookmarks, userReactions] = await Promise.all([
868→        supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
869→        supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
870→        supabase.from('reactions').select('journal_id, reaction_type').in('journal_id', journalIds).eq('user_id', userId)
871→    ]);
872→
873→    const userHasLikedSet = new Set(userLikes.data?.map(j => j.journal_id) || []);
874→    const userHasBookmarkedSet = new Set(userBookmarks.data?.map(j => j.journal_id) || []);
875→    const userReactionMap = new Map((userReactions.data || []).map(r => [r.journal_id, r.reaction_type]));
876→
877→    await attachRepostSources(data);
878→
879→    const formattedData = data.map(journal => ({
880→        ...journal,
881→        has_liked: userHasLikedSet.has(journal.id),
882→        has_bookmarked: userHasBookmarkedSet.has(journal.id),
883→        user_reaction: userReactionMap.get(journal.id) || null
884→    }));
885→
886→    const hasMore = data.length > parsedLimit;
887→    const slicedData = hasMore ? formattedData.slice(0, parsedLimit) : formattedData;
888→
889→    return { data: slicedData, hasMore };

