391→            throw {status: 500, error: 'supabase error while deleting follow data'};
392→        }
393→
394→        return {message: 'deleted follows data'};
395→    } else {
396→        const data = {
397→            follower_id: followerId,
398→            following_id: followingId,
399→        }
